create table if not exists professional_performance_metrics (id uuid primary key, tenant_id uuid not null, branch_id uuid not null, professional_id uuid not null, revenue numeric(12,2), appointments int, ticket_avg numeric(12,2), return_rate numeric(5,2), rating numeric(3,2), avg_service_minutes int, delays int, cancellations int, commission numeric(12,2), snapshot_date date not null);
create table if not exists professional_ranking_history (id uuid primary key, tenant_id uuid not null, branch_id uuid not null, professional_id uuid not null, rank_position int not null, score numeric(8,2), snapshot_date date not null);
create table if not exists professional_goal_progress (id uuid primary key, goal_id uuid not null, professional_id uuid not null, progress_percent numeric(5,2));
create table if not exists professional_feedback_summary (id uuid primary key, tenant_id uuid not null, professional_id uuid not null, average_rating numeric(3,2), praises int, complaints int, updated_at timestamptz default now());
